4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty policy ---
6	  it("quote with empty item list returns premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for single main items (with 5 G fee, newcomer 10% first-insurance) ---
15	  // Note: a single-item quote for a newcomer with 0 years is the minimal sensible scenario.
16	  // To keep the simplest tests truly simple, we test the base-premium examples through
17	  // long-standing-customer follow-up scenarios where only the base + fee apply.
18	  // We test base premiums first via the spec examples about building blocks (which are
19	  // explicitly described as "base premiums"). So we start there.
20	
21	  // --- Building block of 3 alike components (base premium examples from spec) ---
22	  it.todo("2 runes have base premium 50 G (2 x 25 G, no block)");
23	  it.todo("3 runes have base premium 60 G (block applies)");
24	  it.todo("4 runes have base premium 100 G (no block — block requires exactly 3)");
25	  it.todo("7 runes have base premium 175 G (no block possible across 7)");
26	
27	  // --- "Alike" components clarification (❓ same type, not same family) ---
28	  it.todo("2 runes + 1 moonstone have base premium 75 G (no block — different types)");
29	  it.todo("3 runes + 3 moonstones have base premium 120 G (two separate blocks of 3 same type)");
30	
31	  // --- Modifier thresholds ---
32	  it.todo("customer with exactly 2 years receives loyalty discount");
33	  it.todo("sword with exactly enchantment 5 gets high-enchantment surcharge");
34	  it.todo("sword with enchantment 4 does NOT get high-enchantment surcharge");
35	  it.todo("cursed sword with enchantment 5 gets both curse and high-enchantment surcharges");
36	
37	  // --- Rounding rules ---
38	  it.todo("premium calculation yielding 197.5 G rounds UP to 198 G (MHPCO favor)");
39	  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G (MHPCO favor)");
40	  it.todo("intermediate amounts are kept as fractions; only the final premium/payout is rounded");
41	
42	  // --- Modifier scope on multi-item policies (❓ item-specific vs policy-wide) ---
43	  it.todo("policy with cursed sword (100 G base) + plain amulet (60 G base) has policy base 160 G; curse adds 50 G (50% of sword base, not policy total) → 210 G before further modifiers and fee");
44	  it.todo("item-specific modifiers (cursed, high enchantment) apply to the affected item's base premium");
45	  it.todo("policy-wide modifiers (loyalty, first insurance, follow-up contract) apply to the policy base premium");
46	  it.todo("processing fee is added at the very end after all other modifiers");
47	
48	  // --- Integration example 1: Newcomer with cursed sword ---
49	  it.todo("newcomer (0 years, no previous contract) with cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance = 160 + 5 fee)");
50	
51	  // --- Integration example 2: Long-standing customer's second contract ---
52	  it.todo("long-standing customer (3 years, 2nd quote) with cursed sword (steel, ench 7) → premium 160 G (100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first-insurance - 15 follow-up = 155 + 5 fee)");
53	  it.todo("first-insurance surcharge applies to every item in every quote, regardless of customer history (❓ clarification)");
54	
55	  // --- Claim processing: standard reimbursement (no special clauses) ---
56	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
57	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full minus 100 deductible; no special clause)");
58	
59	  // --- Claim processing: deductible per damage event ---
60	  it.todo("dragon attack damages insured sword (500 G) and amulet (300 G) → payout 600 G (100 deductible per item)");
61	
62	  // --- Enchantment threshold vs. dragon material ---
63	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause: 50%, then deductible)");
64	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon material, then deductible: 500 - 100)");
65	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause: full, then deductible: 800 - 100)");
66	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause: 50%, then deductible: 500 - 100)");
67	
68	  // --- Multiple items of the same type (❓ two swords) ---
69	  it.todo("policy covers two swords → insurance sum 2000 G (= 2 x 1000)");
70	  it.todo("dragon attack damages both swords; each damages entry treated as separate damage with own deductible");
71	  it.todo("damages array contains more entries of a type than the policy covers → whole claim rejected (non-zero exit)");
72	
73	  // --- Edge cases ---
74	  it.todo("quote includes item with unknown type (e.g. broomstick) → non-zero exit, error on stderr, no results on stdout");
75	  it.todo("claim references damage entry for an item not part of the policy (e.g. amulet damaged when only sword insured) → non-zero exit, error on stderr");
76	  it.todo("claim references damage entry with unknown item type → non-zero exit, error on stderr");
77	  it.todo("claim contains a damage entry with amount -200 → non-zero exit, error on stderr");
